import React, { useState } from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import './Navbar.css';

const navItems = [
  { path: '/', label: '🏠 Početna' },
  { path: '/casovi', label: '📚 Časovi' },
  { path: '/zakazivanje', label: '📅 Zakaži čas' },
  { path: '/moji-casovi', label: '⭐ Moji časovi' },
  { path: '/vezbanje', label: '🧮 Vežbanje' },
];

export default function Navbar() {
  const [menuOpen, setMenuOpen] = useState(false);
  const navigate = useNavigate();

  return (
    <nav className="navbar">
      <div className="navbar-inner">
        {/* Logo */}
        <div className="navbar-logo" onClick={() => navigate('/')}>
          <span className="logo-math">∑</span>
          <span className="logo-text">Matema<span className="logo-accent">TI</span>&amp;JA</span>
        </div>

        {/* Hamburger */}
        <button
          className={`hamburger ${menuOpen ? 'open' : ''}`}
          onClick={() => setMenuOpen(!menuOpen)}
          aria-label="Meni"
        >
          <span /><span /><span />
        </button>

        {/* Nav links */}
        <ul className={`navbar-links ${menuOpen ? 'open' : ''}`}>
          {navItems.map(item => (
            <li key={item.path}>
              <NavLink
                to={item.path}
                end={item.path === '/'}
                className={({ isActive }) => `nav-link ${isActive ? 'active' : ''}`}
                onClick={() => setMenuOpen(false)}
              >
                {item.label}
              </NavLink>
            </li>
          ))}
        </ul>

        {/* Auth buttons */}
        <div className="navbar-auth">
          <button className="btn-login" onClick={() => { navigate('/prijava'); setMenuOpen(false); }}>
            Prijavi se
          </button>
          <button className="btn-register" onClick={() => { navigate('/registracija'); setMenuOpen(false); }}>
            Registruj se
          </button>
        </div>
      </div>
    </nav>
  );
}
